import React, { useEffect } from 'react';
import { motion } from 'framer-motion';


const trendingBooks = [
  {
    id: 1,
    title: 'Atomic Habits',
    author: 'James Clear',
    rating: 4.8,
    description: 'An easy & proven way to build good habits & break bad ones.',
    imageUrl: 'data:image/jpeg;base64,',
    bookLink: 'https://dn790007.ca.archive.org/0/items/atomic-habits-pdfdrive/Atomic%20habits%20%28%20PDFDrive%20%29.pdf', 
  },
  {
    id: 2,
    title: 'The Alchemist',
    author: 'Paulo Coelho',
    rating: 4.6,
    description: 'A journey of self-discovery and following your dreams.',
    imageUrl: 'data:image/jpeg;base64,',
    bookLink: 'https://icrrd.com/public/media/15-05-2021-084550The-Alchemist-Paulo-Coelho.pdf',
  },
  {
    id: 3,
    title: 'The Ramayana',
    author: 'Valmiki',
    rating: 4.9,
    description: 'An ancient Indian epic narrating the life of Prince Rama.',
    imageUrl: 'https://shorturl.at/UZByL',
    bookLink: 'https://archive.org/download/ramayanaofvalmik01valm/ramayanaofvalmik01valm.pdf',
  },
  {
    id: 4,
    title: 'Clean Code',
    author: 'Robert C. Martin',
    rating: 4.7,
    description: 'A handbook of agile software craftsmanship, emphasizing writing clean and maintainable code.',
    imageUrl: 'https://shorturl.at/KDPZ7',
    bookLink: 'https://book.northwind.ir/bookfiles/clean-code-a-handbook-of-agile-software-craftsmanship/Clean.Code.A.Handbook.of.Agile.Software.Craftsmanship.pdf',
  },
  {
    id: 5,
    title: 'Mahabharata',
    author: 'Vyasa',
    rating: 4.5,
    description: 'The grand epic of ancient India, exploring duty, righteousness, and the complexities of human nature.',
    imageUrl: 'https://shorturl.at/zqmKJ',
    bookLink: 'https://ia803400.us.archive.org/7/items/the-complete-mahabharata/The%20Complete%20Mahabharata%20.pdf',
  },
  {
    id: 6,
    title: 'Ready Player One',
    author: 'Ernest Cline',
    rating: 4.4,
    description: 'A dystopian novel set in a virtual reality world filled with 80s pop culture references.',
    imageUrl: 'data:image/jpeg;base64,',
    bookLink: 'https://asmsummerreading.weebly.com/uploads/1/2/5/7/125763472/ready-player-one.pdf',
  },
];


const loopedBooks = [...trendingBooks, ...trendingBooks];

const BookCard = ({ title, author, rating, description, imageUrl, bookLink }) => {
  const handleLocateClick = () => {
    if (bookLink) {
      window.open(bookLink, '_blank', 'noopener,noreferrer');
    } else {
      alert('Book link not available.');
    }
  };

  return (
    <div className="flex-shrink-0 w-72 mx-4">
      <div className="bg-white rounded-2xl shadow-lg overflow-hidden transform transition-all duration-300 hover:scale-105 hover:shadow-2xl">
        <img
          src={imageUrl}
          alt={title}
          className="w-full h-80 object-cover"
        />
        <div className="p-4">
          <h3 className="text-xl font-bold text-teal-700 truncate">{title}</h3>
          <p className="text-gray-600 text-sm mb-1">by {author}</p>
          <p className="text-yellow-500 font-semibold mb-2">⭐ {rating}</p>
          <p className="text-gray-700 text-sm line-clamp-3 mb-3">{description}</p>
          
          {/* ✅ Locate Button with Book Link */}
          <button
            onClick={handleLocateClick}
            className="bg-teal-500 hover:bg-teal-800 text-white font-semibold py-2 px-4 rounded-md w-full transition duration-200"
          >
            Locate
          </button>
        </div>
      </div>
    </div>
  );
};

// --- Main Component ---
const TrendingBooks = () => {
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  return (
    <motion.div
      className="min-h-screen bg-white text-gray-900"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.7 }}
    >
      {/* --- Header --- */}
      <div className="container mx-auto max-w-5xl px-4 pt-16 md:pt-24 text-center">
        <motion.h1
          className="text-4 xl md:text-6xl text-bold font-serif text-center mb-8 text-teal-600"
           initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
        >
          Trending Books    
        </motion.h1>
        <motion.p
          className="text-lg md:text-xl text-gray-900 mb-12"
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ delay: 0.3, duration: 0.6 }}
        >
          
        </motion.p>
      </div>

      {/* --- Infinite Scrolling Books --- */}
      <div className="overflow-hidden relative py-12">
        <motion.div
          className="flex whitespace-nowrap"
          animate={{ x: ['0%', '-50%'] }}
          transition={{ ease: 'linear', duration: 30, repeat: Infinity }}
        >
          {loopedBooks.map((book, index) => (
            <BookCard
              key={`${book.id}-${index}`}
              title={book.title}
              author={book.author}
              rating={book.rating}
              description={book.description}
              imageUrl={book.imageUrl}
              bookLink={book.bookLink}
            />
          ))}
        </motion.div>

        {/* Edge Fades */}
        <div className="absolute top-0 left-0 w-32 h-full bg-gradient-to-r from-white to-transparent pointer-events-none" />
        <div className="absolute top-0 right-0 w-32 h-full bg-gradient-to-l from-white to-transparent pointer-events-none" />
      </div>
    </motion.div>
  );
};

export default TrendingBooks;





















